import os
from collections import defaultdict

def get_large_files_by_ext(path, threshold=102400):
    large_files_by_ext = defaultdict(list)
    for root, dirs, files in os.walk(path):
        for f in files:
            filepath = os.path.join(root, f)
            ext = os.path.splitext(f)[1]
            size = os.path.getsize(filepath)
            if size > threshold:
                large_files_by_ext[ext].append(filepath)

    return large_files_by_ext

if __name__ == '__main__':
    large_files_by_ext = get_large_files_by_ext('/var/www/html')
    for ext, files in large_files_by_ext.items():
        print(f'{len(files)} large {ext} files')

